import { GoogleGenAI, Type } from "@google/genai";
import { Contributor, Transaction } from '../types';
import { Logger } from "./monitoringService";

const getAIClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.error("CRITICAL: Gemini API Key is missing.");
        throw new Error("Chave de API do Gemini não configurada no ambiente.");
    }
    return new GoogleGenAI({ apiKey });
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 3, delay = 4000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const msg = error?.message?.toLowerCase() || "";
        if (msg.includes("requested entity was not found")) {
             if (retries <= 0) throw error;
             if (typeof window !== 'undefined' && (window as any).aistudio) {
                 try {
                     await (window as any).aistudio.openSelectKey();
                     return callWithSimpleRetry(fn, retries - 1, delay); 
                 } catch (e) { throw error; }
             }
        }
        if (retries > 0) {
            await new Promise(r => setTimeout(r, delay));
            return callWithSimpleRetry(fn, retries - 1, delay);
        }
        throw error;
    }
};

/**
 * MOTOR DE EXTRAÇÃO DE BLOCO (Especialista em PDFs sem colunas definidas)
 */
export const extractTransactionsFromComplexBlock = async (rawText: string): Promise<any[]> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `VOCÊ É UM ANALISTA BANCÁRIO ESPECIALISTA EM EXTRAÇÃO DE DADOS TABULARES DE TEXTO DESESTRUTURADO.
        O texto abaixo veio de um PDF bancário onde as colunas se misturaram.

        TEXTO DO DOCUMENTO:
        ${rawText.substring(0, 10000)}

        SUAS INSTRUÇÕES CRÍTICAS:
        1. Identifique cada transação financeira individual.
        2. REAGRUPE as descrições: Se o nome do favorecido ou o CPF estiverem em linhas logo abaixo do tipo de transação (Ex: "PIX RECEBIDO" na linha 1 e "JOAO DA SILVA" na linha 2), combine-os em uma única descrição clara.
        3. Identifique o valor: Procure por números decimais. Atente-se ao sinal ou letra: "C" ou valor positivo é ENTRADA, "D" ou sinal "-" é SAÍDA (valor negativo).
        4. Converta as datas encontradas para o formato ISO YYYY-MM-DD. Se o ano não estiver claro, use 2025.

        REGRAS DO JSON DE SAÍDA:
        - "date": String (YYYY-MM-DD)
        - "description": Nome limpo e completo da transação (Ex: "PIX RECEBIDO JOAO DA SILVA")
        - "amount": Number (Float, positivo para crédito, negativo para débito)
        - "type": String curta (Ex: PIX, TED, DOC, TARIFA)

        RETORNE EXCLUSIVAMENTE UM JSON ARRAY: [{date, description, amount, type}]`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0.1,
                responseMimeType: "application/json"
            }
        });

        const text = response.text?.trim() || "[]";
        try {
            return JSON.parse(text);
        } catch (e) {
            console.error("Erro ao parsear resposta da IA em bloco:", text);
            return [];
        }
    });
};

/**
 * Extrai dados estruturados baseado em um exemplo de correção do usuário.
 */
export const extractStructuredDataByExample = async (rawText: string, instruction: string): Promise<any> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `${instruction}\n\nTEXTO:\n${rawText}`,
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    amount: { type: Type.NUMBER },
                                    type: { type: Type.STRING }
                                }
                            }
                        }
                    }
                }
            }
        });
        return response.text ? JSON.parse(response.text) : { rows: [] };
    });
};

/**
 * Sugere o mapeamento inicial de um arquivo.
 */
export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `AJA COMO UM ARQUITETO DE DADOS FINANCEIROS. Analise as primeiras linhas deste extrato.

        CRITÉRIO DE DECISÃO:
        - Se as transações ocupam apenas uma linha e possuem delimitadores claros (como ; ou tab), use extractionMode: "COLUMNS".
        - Se a descrição de uma transação se quebra em várias linhas ou os valores estão "soltos" à direita sem delimitador, use extractionMode: "BLOCK".

        DADOS:
        ${sampleText.substring(0, 6000)}

        RETORNE ESTE JSON:
        {
          "extractionMode": "COLUMNS" | "BLOCK",
          "dateColumnIndex": number (se COLUMNS),
          "descriptionColumnIndex": number (se COLUMNS),
          "amountColumnIndex": number (se COLUMNS),
          "typeColumnIndex": number | null,
          "skipRowsStart": number
        }`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { temperature: 0.1, responseMimeType: "application/json" }
        });

        return response.text ? JSON.parse(response.text) : null;
    });
};

export const getAISuggestion = async (transaction: Transaction, contributors: Contributor[]): Promise<string> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `Analise: "${transaction.description}". Qual contribuinte melhor se encaixa? Lista: [${contributors.map(c => c.name).join(', ')}]. Responda apenas o nome.`;
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { temperature: 0.1 }
        });
        return response.text ? response.text.trim() : "Nenhuma sugestão clara";
    });
};

