const getAIClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.error("CRITICAL: Gemini API Key is missing.");
        throw new Error("Chave de API do Gemini não configurada no ambiente.");
    }
    return new GoogleGenAI({ apiKey });
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 3, delay = 4000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const msg = error?.message?.toLowerCase() || "";
        if (msg.includes("requested entity was not found")) {
             if (retries <= 0) throw error;
             if (typeof window !== 'undefined' && (window as any).aistudio) {
                 try {
                     await (window as any).aistudio.openSelectKey();
                     return callWithSimpleRetry(fn, retries - 1, delay); 
                 } catch (e) { throw error; }
             }
        }
        if (retries > 0) {
            await new Promise(r => setTimeout(r, delay));
            return callWithSimpleRetry(fn, retries - 1, delay);
        }
        throw error;
    }
};

/**
 * MOTOR DE EXTRAÇÃO DE BLOCO (V2 - FIDELIDADE LITERAL)
 */
export const extractTransactionsFromComplexBlock = async (rawText: string): Promise<any[]> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `VOCÊ É UM PARSER BANCÁRIO DE ALTA FIDELIDADE. 
        Sua única missão é transcrever dados do texto para JSON sem NENHUMA modificação.

        TEXTO DO DOCUMENTO:
        ${rawText.substring(0, 10000)}

        REGRAS OBRIGATÓRIAS DE EXTRAÇÃO:
        1. DESCRIÇÃO LITERAL: Capture o nome do favorecido e o histórico EXATAMENTE como aparecem. Se houver um CPF, código ou abreviação, MANTENHA-OS. Proibido resumir.
        2. VALORES REAIS: Capture o número decimal e determine o sinal. "C" ou positivo = ENTRADA. "D" ou "-" = SAÍDA.
        3. DATAS: Converta para ISO YYYY-MM-DD. Se faltar o ano, use 2025.
        4. NÃO FILTRE: Se o texto parece uma transação, extraia-a.

        PROIBIÇÕES:
        - Não remova palavras como "PIX", "TED" ou códigos da descrição.
        - Não tente "limpar" o nome do favorecido.
        - Entregue o texto BRUTO no campo "description".

        FORMATO DE SAÍDA (ARRAY JSON): 
        [{ "date": "YYYY-MM-DD", "description": "TEXTO_EXATO_DO_DOCUMENTO", "amount": number, "type": "CATEGORIA" }]`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0, // Determinismo máximo
                responseMimeType: "application/json"
            }
        });

        const text = response.text?.trim() || "[]";
        try {
            return JSON.parse(text);
        } catch (e) {
            console.error("Erro ao parsear resposta literal da IA:", text);
            return [];
        }
    });
};

