import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { RowValidator } from '../core/processors/RowValidator';
import { TypeResolver } from '../core/processors/TypeResolver';
import { extractTransactionsFromComplexBlock } from '../services/geminiService';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);
    const [isSimulating, setIsSimulating] = useState(false);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');

    const runSimulation = useCallback(async () => {
        if (!gridData || gridData.length === 0) {
            setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || { extractionMode: 'COLUMNS', dateColumnIndex: -1, descriptionColumnIndex: -1, amountColumnIndex: -1, skipRowsStart: 0 };
        setIsSimulating(true);

        try {
            // MODO NOVO: EXTRAÇÃO DE BLOCO (Contextual IA)
            if (mapping.extractionMode === 'BLOCK') {
                const textForAi = gridData.slice(0, 100).map(row => row.join(' ')).join('\n');
                const aiResult = await extractTransactionsFromComplexBlock(textForAi);

                if (aiResult && aiResult.length > 0) {
                    setProcessedTransactions(aiResult.map((tx, i) => ({
                        ...tx,
                        id: `block-sim-${i}-${Date.now()}`,
                        rawDescription: tx.description,
                        cleanedDescription: tx.description,
                        originalAmount: String(tx.amount),
                        isValid: true,
                        status: 'valid'
                    })));
                } else {
                    setProcessedTransactions([]);
                }
                return;
            }

            // MODO TRADICIONAL: COLUNAS FIXAS
            const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, paymentMethodColumnIndex, skipRowsStart } = mapping;
            const newTransactions: SafeTransaction[] = [];
            const yearAnchor = DateResolver.discoverAnchorYear(gridData);

            gridData.forEach((cols, index) => {
                if (!RowValidator.isPotentialRow(cols)) return;
                const isSkipped = index < (skipRowsStart || 0);

                if (dateColumnIndex === -1 && descriptionColumnIndex === -1 && amountColumnIndex === -1) {
                    newTransactions.push({ id: `sim-raw-${index}`, date: "---", description: cols.join(' | ').substring(0, 80), rawDescription: cols.join('|'), amount: 0, originalAmount: "0.00", cleanedDescription: cols.join(' | '), contributionType: "BRUTO", paymentMethod: "BRUTO", sourceIndex: index, isValid: false, status: 'pending' });
                    return;
                }

                const rawDate = (cols[dateColumnIndex] || '').trim();
                const rawDesc = (cols[descriptionColumnIndex] || '').trim();
                const rawAmount = (cols[amountColumnIndex] || '').trim();

                const rawForm = (paymentMethodColumnIndex !== undefined && cols[paymentMethodColumnIndex])
                    ? cols[paymentMethodColumnIndex].trim().toUpperCase()
                    : TypeResolver.resolveFromDescription(rawDesc);

                const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                const amountStr = AmountResolver.clean(rawAmount);
                const amount = parseFloat(amountStr);
                const isValid = RowValidator.isValid(isoDate, rawDesc, amountStr) && !isSkipped;

                newTransactions.push({ 
                    id: `sim-${index}-${Date.now()}`,
                    date: isoDate || rawDate || "---", 
                    description: rawDesc || "---", 
                    rawDescription: rawDesc || "---", 
                    paymentMethod: rawForm,
                    amount: isNaN(amount) ? 0 : amount, 
                    originalAmount: rawAmount, 
                    cleanedDescription: rawDesc,
                    contributionType: 'AUTO', 
                    sourceIndex: index, 
                    isValid, 
                    status: isSkipped ? 'ignored' : (isValid ? 'valid' : 'error') 
                });
            });
            setProcessedTransactions(newTransactions);
        } catch (e) {
            console.error("Simulation error:", e);
        } finally {
            setIsSimulating(false);
        }
    }, [gridData, activeMapping]);

    useEffect(() => {
        const dataHash = gridData.length > 0 ? `${gridData.length}-${gridData[0].join('|').substring(0, 50)}` : 'empty';
        const mappingKey = JSON.stringify(activeMapping);
        if (dataHash !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataHash;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    return {
        processedTransactions,
        isSimulating,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit: (tx: any, idx: number) => { setEditingRowIndex(idx); setEditingRowData({ ...tx }); },
        saveRow: (onLearned?: any) => {
            if (editingRowIndex !== null && editingRowData) {
                const updatedTx = { ...editingRowData, status: 'edited' as const, isValid: true };
                setProcessedTransactions(prev => { const n = [...prev]; n[editingRowIndex] = updatedTx; return n; });
                if (onLearned && editingRowData.sourceIndex !== undefined) onLearned(gridData[editingRowData.sourceIndex], updatedTx);
                setEditingRowIndex(null);
            }
        },
        cancelEdit: () => setEditingRowIndex(null)
    };
};

import { Transaction, FileModel } from '../../types';
import { Fingerprinter } from '../processors/Fingerprinter';
import { StrategyEngine } from '../strategies';
import { NameResolver } from '../processors/NameResolver';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';

/**
 * 🎛️ INGESTION ORCHESTRATOR (V5 - PDF LOYALTY FIX)
 * --------------------------------------------------------------------------
 * Garante fidelidade absoluta entre o treinamento e o processamento real.
 */

export interface IngestionResult {
    source: 'upload' | 'gmail';
    transactions: Transaction[];
    strategyUsed: string;
    fingerprint: any;
    appliedModelId?: string;
}

export const IngestionOrchestrator = {
    /**
     * Porta 1: Processamento de Arquivos Físicos (PDF, CSV, Excel, TXT)
     */
    async processFile(
        file: File, 
        content: string, 
        models: FileModel[], 
        globalKeywords: string[]
    ): Promise<IngestionResult> {
        // 1. NORMALIZAÇÃO ESTRUTURAL OBRIGATÓRIA PARA PDF / TEXTO
        // Transformamos sequências de espaços em delimitadores virtuais (;)
        // Isso é CRITICAL: Garante que as colunas mapeadas no Laboratório (0, 1, 2) existam aqui.
        let processedContent = content;
        const fileNameLower = file.name.toLowerCase();
        const isPdf = fileNameLower.endsWith('.pdf');

        // Se for PDF ou se o texto tiver muitos espaços e nenhum delimitador padrão
        if (isPdf || (content.includes('   ') && !content.includes(';') && !content.includes('\t'))) {
            processedContent = content
                .split(/\r?\n/)
                .map(line => {
                    const trimmed = line.trim();
                    if (!trimmed) return "";
                    // REGRA DE OURO: Converte 2 ou mais espaços em ponto e vírgula (Colunas Virtuais)
                    return trimmed.replace(/\s{2,}/g, ';');
                })
                .filter(line => line.length > 0)
                .join('\n');
        }

        // 2. GERAÇÃO DE DNA (Fingerprint) sobre o conteúdo normalizado
        const fingerprint = Fingerprinter.generate(processedContent);

        // 3. ROTEAMENTO DE ESTRATÉGIA
        const result = await StrategyEngine.process(file.name, processedContent, models, globalKeywords);

        return {
            source: 'upload',
            transactions: result.transactions,
            strategyUsed: result.strategyName,
            fingerprint: fingerprint || { columnCount: 0 }
        };
    },

    /**
     * Porta 2: Processamento de Dados Virtuais (Gmail / API Sync)
     */
    async processVirtualData(
        sourceName: string,
        data: any[],
        globalKeywords: string[]
    ): Promise<IngestionResult> {
        const yearAnchor = new Date().getFullYear();

        const transactions: Transaction[] = data.map((item, index) => {
            const rawDesc = item.description || item.memo || 'Sem descrição';
            const rawAmount = String(item.amount);

            const cleanedDesc = NameResolver.clean(rawDesc, globalKeywords);
            const isoDate = DateResolver.resolveToISO(item.date, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);

            return {
                id: `gmail-sync-${Date.now()}-${index}`,
                date: isoDate,
                description: rawDesc.trim(),
                rawDescription: `GMAIL_ORIGIN: ${rawDesc.trim()}`,
                amount: parseFloat(amountStr),
                originalAmount: rawAmount,
                cleanedDescription: cleanedDesc,
                contributionType: item.type || 'PIX'
            };
        }).filter(t => t.date && !isNaN(t.amount));

        const virtualContent = transactions.map(t => `${t.date};${t.description};${t.amount}`).join('\n');
        const fingerprint = Fingerprinter.generate(virtualContent) || { source: 'gmail_api' };

        return {
            source: 'gmail',
            transactions,
            strategyUsed: 'GATEWAY_IA_GMAIL',
            fingerprint: { ...fingerprint, is_virtual: true }
        };
    }
};

import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';
import { extractTransactionsFromComplexBlock } from '../services/geminiService';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

/**
 * DATABASE MODEL STRATEGY (V10 - FIDELIDADE ABSOLUTA E PERSISTENTE)
 */
export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
                (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
                (m.fingerprint.dataTopology === fileFp.dataTopology)
            )
        );
    },
    parse: async (content, yearAnchor, models, globalKeywords = []) => {
        if (!models || models.length === 0) return [];

        const fileFp = Fingerprinter.generate(content);
        const matchingModel = models.find(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp?.headerHash) || 
                (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                (m.fingerprint.dataTopology === fileFp?.dataTopology)
            )
        );

        if (!matchingModel) return [];

        // MODO 1: EXTRAÇÃO DE BLOCO (IA CONTEXTUAL)
        const extractionMode = (matchingModel.mapping as any).extractionMode;
        if (extractionMode === 'BLOCK') {
            const results = await extractTransactionsFromComplexBlock(content);
            return results.map((t, i) => ({
                id: `db-block-${matchingModel.id}-${i}-${Date.now()}`,
                date: t.date,
                description: t.description,
                rawDescription: t.description,
                paymentMethod: t.paymentMethod || 'OUTROS',
                amount: t.amount,
                originalAmount: String(t.amount),
                cleanedDescription: t.description, 
                contributionType: t.type || 'AUTO'
            }));
        }

        // MODO 2: COLUNAS FIXAS (MAIS COMUM EM PDF NORMALIZADO)
        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = matchingModel.mapping;
        const paymentMethodColumnIndex = matchingModel.mapping.paymentMethodColumnIndex;

        // IMPORTANTE: PDFs normalizados SEMPRE usam ';' como delimitador virtual
        const delimiter = content.includes(';') ? ';' : (matchingModel.fingerprint.delimiter || ';');

        lines.forEach((line, index) => {
            if (index < (skipRowsStart || 0)) return;
            const cols = line.split(delimiter);

            if (cols.length > Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) {
                const rawDate = (cols[dateColumnIndex] || '').trim();
                const rawDesc = (cols[descriptionColumnIndex] || '').trim();
                const rawAmount = (cols[amountColumnIndex] || '').trim();

                const rawForm = (paymentMethodColumnIndex !== undefined && cols[paymentMethodColumnIndex])
                    ? cols[paymentMethodColumnIndex].trim().toUpperCase()
                    : TypeResolver.resolveFromDescription(rawDesc);

                const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                const standardizedAmount = AmountResolver.clean(rawAmount);
                const numericValue = parseFloat(standardizedAmount);

                if (rawDesc.length > 0 || !isNaN(numericValue)) {
                    transactions.push({
                        id: `dbmodel-${matchingModel.id}-${index}-${Date.now()}`,
                        date: isoDate || (rawDate ? `ERR:${rawDate}` : new Date().toISOString().split('T')[0]),
                        description: rawDesc,
                        rawDescription: rawDesc,
                        paymentMethod: rawForm,
                        amount: isNaN(numericValue) ? 0 : numericValue,
                        originalAmount: rawAmount,
                        cleanedDescription: rawDesc, 
                        contributionType: typeColumnIndex !== undefined && cols[typeColumnIndex] 
                            ? cols[typeColumnIndex].trim().toUpperCase() 
                            : TypeResolver.resolveFromDescription(rawDesc)
                    });
                }
            }
        });

        return transactions;
    }
};

/**
 * GENERIC STRATEGY (Fallback)
 */
export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords) => {
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return [];

        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));

        const dIdx = DateResolver.identifyDateColumn(rows);
        const aIdx = AmountResolver.identifyAmountColumn(rows, [dIdx]);
        const nIdx = NameResolver.identifyNameColumn(rows, [dIdx, aIdx]);

        if (dIdx === -1 || aIdx === -1) return [];

        return rows.map((row, i) => {
            const date = DateResolver.resolveToISO(row[dIdx], yearAnchor);
            const amountStr = AmountResolver.clean(row[aIdx]);
            const amount = parseFloat(amountStr);

            if (!date || isNaN(amount) || amount === 0) return null;

            const rawDesc = row[nIdx] || 'S/D';
            return {
                id: `gen-${i}-${Date.now()}`, 
                date, 
                amount,
                description: rawDesc, 
                rawDescription: rawDesc,
                originalAmount: row[aIdx], 
                paymentMethod: TypeResolver.resolveFromDescription(rawDesc),
                cleanedDescription: NameResolver.clean(rawDesc, globalKeywords),
                contributionType: TypeResolver.resolveFromDescription(rawDesc)
            } as Transaction;
        }).filter((t): t is Transaction => t !== null);
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<{ transactions: Transaction[], strategyName: string }> => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        let targetModel = overrideModel;
        if (!targetModel) {
            const fileFp = Fingerprinter.generate(content);
            targetModel = models.find(m => 
                m.is_active && (
                    (m.fingerprint.headerHash === fileFp?.headerHash && m.fingerprint.headerHash !== null) ||
                    (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                    (m.fingerprint.dataTopology === fileFp?.dataTopology)
                )
            );
        }

        if (targetModel) {
            const result = await DatabaseModelStrategy.parse(content, yearAnchor, [targetModel], globalKeywords);
            return { transactions: result as Transaction[], strategyName: targetModel.name };
        }

        const genResult = GenericStrategy.parse(content, yearAnchor, models, globalKeywords) as Transaction[];
        return { transactions: genResult, strategyName: 'Genérico' };
    }
};

import { useState, useCallback } from 'react';
import { 
    MatchResult, 
    Transaction, 
    Contributor, 
    Church, 
    Bank, 
    FileModel, 
    ComparisonType,
    ContributorFile,
    GroupedReportData,
    ReconciliationStatus
} from '../types';
import { 
    processFileContent, 
    parseContributors, 
    matchTransactions, 
    groupResultsByChurch,
    PLACEHOLDER_CHURCH
} from '../services/processingService';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';
import { getAISuggestion } from '../services/geminiService';
import { useLiveListSync } from './useLiveListSync';

interface UseReconciliationProps {
    user: any;
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: any[];
    showToast: (msg: string, type: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: any) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    const [activeBankFiles, setBankStatementFile] = useState<any[]>([]);
    const [contributorFiles, setContributorFiles] = useState<ContributorFile[]>([]);
    const [selectedBankIds, setSelectedBankIds] = useState<string[]>([]);
    const [matchResults, setMatchResults] = useState<MatchResult[]>([]);
    const [reportPreviewData, setReportPreviewData] = useState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(null);
    const [activeReportId, setActiveReportId] = useState<string | null>(null);
    const [hasActiveSession, setHasActiveSession] = useState(false);
    const [comparisonType, setComparisonType] = useState<ComparisonType>('income');
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[]>([]);

    const [uiFeedback, setUiFeedback] = useState({
        loadingAiId: null as string | null,
        aiSuggestion: null as { id: string; name: string } | null,
        isRecompareModalOpen: false,
        pendingTraining: null as any | null
    });

    const { persistTransactions, clearRemoteList } = useLiveListSync({
        user,
        setBankStatementFile,
        setSelectedBankIds,
        showToast
    });

    const regenerateReportPreview = useCallback((results: MatchResult[]) => {
        const uniqueMap = new Map<string, MatchResult>();
        results.forEach(r => uniqueMap.set(r.transaction.id, r));
        const uniqueResults = Array.from(uniqueMap.values());

        const incomeResults = uniqueResults.filter(r => 
            r.transaction.amount >= 0 || 
            r.status === ReconciliationStatus.PENDING
        );

        const expenseResults = uniqueResults.filter(r => 
            r.transaction.amount < 0 && 
            r.status !== ReconciliationStatus.PENDING
        );

        setReportPreviewData({
            income: groupResultsByChurch(incomeResults),
            expenses: { 'all_expenses_group': expenseResults }
        });
    }, []);

    const handleStatementUpload = useCallback(async (content: string, fileName: string, bankId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            // FIX: Passamos o arquivo real para o IngestionOrchestrator para detecção de PDF precisa
            const fileObj = rawFile || new File([content], fileName, { type: 'text/plain' });
            const result = await IngestionOrchestrator.processFile(fileObj, content, fileModels, customIgnoreKeywords);
            const processedTransactions = result.transactions;

            if (processedTransactions.length === 0) {
                showToast("Nenhuma transação encontrada.", "error");
                return;
            }

            await persistTransactions(bankId, processedTransactions);

            setBankStatementFile(prev => {
                const filtered = prev.filter(f => f.bankId !== bankId);
                return [...filtered, { 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile: fileObj, 
                    processedTransactions,
                    fingerprint: result.fingerprint 
                }];
            });

            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);

            // Log do método utilizado para transparência
            const methodLabel = result.strategyUsed === 'Genérico' ? 'Layout desconhecido' : `Modelo: ${result.strategyUsed}`;
            showToast(`${methodLabel} (${processedTransactions.length} txs)`, "success");
        } catch (error: any) {
            console.error("Ingestion Error:", error);
            showToast("Erro ao processar ingestão.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [fileModels, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const importGmailTransactions = useCallback(async (transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;
        setIsLoading(true);
        try {
            const bankId = 'gmail-sync';
            const result = await IngestionOrchestrator.processVirtualData('Gmail', transactions, customIgnoreKeywords);

            await persistTransactions(bankId, result.transactions);

            setBankStatementFile(prev => [
                ...prev.filter(f => f.bankId !== bankId),
                { 
                    bankId, 
                    fileName: 'Sincronização Gmail', 
                    processedTransactions: result.transactions,
                    content: '',
                    fingerprint: result.fingerprint
                }
            ]);
            setSelectedBankIds(prev => prev.includes(bankId) ? prev : [...prev, bankId]);
            showToast("Gmail sincronizado e normalizado.", "success");
        } catch (e) {
            showToast("Erro na sincronização virtual.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [user, customIgnoreKeywords, persistTransactions, showToast, setIsLoading]);

    const removeBankStatementFile = useCallback((bankId: string) => {
        setBankStatementFile(prev => prev.filter(f => f.bankId !== bankId));
        setSelectedBankIds(prev => prev.filter(id => id !== bankId));
        clearRemoteList(bankId);
    }, [clearRemoteList]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string) => {
        setIsLoading(true);
        try {
            const contributors = parseContributors(content, customIgnoreKeywords, contributionKeywords);
            const church = churches.find(c => c.id === churchId);
            if (contributors.length > 0 && church) {
                setContributorFiles(prev => [...prev.filter(f => f.churchId !== churchId), { church, contributors, fileName, churchId }]);
                showToast("Lista carregada.", "success");
            }
        } catch (error) {
            showToast("Erro ao processar lista.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [churches, customIgnoreKeywords, contributionKeywords, showToast, setIsLoading]);

    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
        showToast("Lista removida.", "success");
    }, [showToast]);

    const toggleBankSelection = useCallback((bankId: string) => {
        setSelectedBankIds(prev => 
            prev.includes(bankId) ? prev.filter(id => id !== bankId) : [...prev, bankId]
        );
    }, []);

    const handleCompare = useCallback(async (
        overrideType?: ComparisonType, 
        overrideSimilarity?: number, 
        overrideTolerance?: number
    ) => {
        setIsLoading(true);
        try {
            const selectedFiles = activeBankFiles.filter(f => selectedBankIds.includes(f.bankId));
            const allTransactions = activeReportId ? matchResults.map(r => r.transaction) : selectedFiles.flatMap(f => f.processedTransactions || []);

            if (allTransactions.length === 0 && !activeReportId) {
                showToast("Sem dados para processar.", "error");
                setIsLoading(false);
                return;
            }

            const finalType = overrideType || comparisonType;
            const finalSimilarity = overrideSimilarity !== undefined ? overrideSimilarity : similarityLevel;
            const finalTolerance = overrideTolerance !== undefined ? overrideTolerance : dayTolerance;

            let transactionsToMatch = [...allTransactions];
            if (finalType === 'income') {
                transactionsToMatch = transactionsToMatch.filter(tx => tx.amount >= 0);
            } else if (finalType === 'expenses') {
                transactionsToMatch = transactionsToMatch.filter(tx => tx.amount < 0);
            }

            const results = matchTransactions(
                transactionsToMatch,
                contributorFiles,
                { similarityThreshold: finalSimilarity, dayTolerance: finalTolerance },
                learnedAssociations,
                churches,
                customIgnoreKeywords
            );

            setMatchResults(results);
            regenerateReportPreview(results);
            setHasActiveSession(true);
            if (!activeReportId) setActiveView('reports');
            showToast("Conciliação concluída!", "success");
        } catch (error) {
            showToast("Erro na conciliação.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [activeBankFiles, selectedBankIds, contributorFiles, similarityLevel, dayTolerance, comparisonType, learnedAssociations, churches, customIgnoreKeywords, activeReportId, matchResults, showToast, setIsLoading, setActiveView, regenerateReportPreview]);

    const updateReportData = useCallback((updatedRow: MatchResult) => {
        setMatchResults(prev => {
            const next = [...prev];
            const index = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
            if (index !== -1) next[index] = updatedRow;
            else next.push(updatedRow);
            if (updatedRow.status === ReconciliationStatus.IDENTIFIED && updatedRow.contributor?._internalId) {
                const ghostId = `ghost-${updatedRow.contributor._internalId}`;
                const gIdx = next.findIndex(r => r.transaction.id === gId && r.status === ReconciliationStatus.PENDING);
                if (gIdx !== -1) next.splice(gIdx, 1);
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const revertMatch = useCallback((txId: string) => {
        setMatchResults(prev => {
            const next = [...prev];
            const idx = next.findIndex(r => r.transaction.id === txId);
            if (idx === -1) return prev;
            const old = next[idx];
            next[idx] = { 
                ...old, 
                status: ReconciliationStatus.UNIDENTIFIED, 
                church: PLACEHOLDER_CHURCH, 
                contributor: null, 
                matchMethod: undefined, 
                similarity: 0,
                contributorAmount: undefined
            };
            if (old.contributor?._internalId) {
                const gId = `ghost-${old.contributor._internalId}`;
                if (!next.some(r => r.transaction.id === gId)) {
                    next.push({
                        transaction: { 
                            id: gId, 
                            date: old.contributor.date || new Date().toISOString().split('T')[0], 
                            description: old.contributor.name, 
                            rawDescription: old.contributor.name, 
                            amount: 0, 
                            cleanedDescription: old.contributor.cleanedName || old.contributor.name, 
                            contributionType: old.contributor.contributionType, 
                            originalAmount: old.contributor.originalAmount || "0.00" 
                        },
                        contributor: old.contributor, 
                        status: ReconciliationStatus.PENDING, 
                        church: old.church, 
                        matchMethod: undefined, 
                        similarity: 0, 
                        contributorAmount: old.contributor.amount 
                    });
                }
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const resetReconciliation = useCallback(async () => {
        setMatchResults([]);
        setReportPreviewData(null);
        setActiveReportId(null);
        setHasActiveSession(false);
        setBankStatementFile([]);
        setContributorFiles([]);
        setSelectedBankIds([]);
        await clearRemoteList();
        showToast("Sistema resetado.", "success");
        setActiveView('upload');
    }, [clearRemoteList, showToast, setActiveView]);

    const handleAnalyze = useCallback(async (tx: Transaction, contributors: Contributor[]) => {
        setUiFeedback(prev => ({ ...prev, loadingAiId: tx.id }));
        try {
            const name = await getAISuggestion(tx, contributors);
            setUiFeedback(prev => ({ ...prev, aiSuggestion: { id: tx.id, name }, loadingAiId: null }));
        } catch (e) {
            setUiFeedback(prev => ({ ...prev, loadingAiId: null }));
        }
    }, []);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        importGmailTransactions,
        ...uiFeedback,
        setUiFeedback,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile,
        removeContributorFile, toggleBankSelection, handleCompare, resetReconciliation,
        revertMatch, updateReportData, handleAnalyze, setMatchResults, setReportPreviewData,
        setBankStatementFile,
        closeManualIdentify: () => {
            setManualIdentificationTx(null);
            setBulkIdentificationTxs([]);
        },
        findMatchResult: (id: string) => matchResults.find(r => r.transaction.id === id),
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        }
    };
};

