            if (!activeReportId) setActiveView('reports');
            showToast("Conciliação concluída!", "success");
        } catch (error) {
            showToast("Erro na conciliação.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [activeBankFiles, selectedBankIds, contributorFiles, similarityLevel, dayTolerance, comparisonType, learnedAssociations, churches, customIgnoreKeywords, activeReportId, matchResults, showToast, setIsLoading, setActiveView, regenerateReportPreview]);

    const updateReportData = useCallback((updatedRow: MatchResult) => {
        setMatchResults(prev => {
            const next = [...prev];
            const index = next.findIndex(r => r.transaction.id === updatedRow.transaction.id);
            if (index !== -1) next[index] = updatedRow;
            else next.push(updatedRow);
            if (updatedRow.status === ReconciliationStatus.IDENTIFIED && updatedRow.contributor?._internalId) {
                // Fixed: Corrected variable usage for 'gId' to remove identifying ghost records from table
                const ghostId = `ghost-${updatedRow.contributor._internalId}`;
                const gIdx = next.findIndex(r => r.transaction.id === ghostId && r.status === ReconciliationStatus.PENDING);
                if (gIdx !== -1) next.splice(gIdx, 1);
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const revertMatch = useCallback((txId: string) => {
        setMatchResults(prev => {
            const next = [...prev];
            const idx = next.findIndex(r => r.transaction.id === txId);
            if (idx === -1) return prev;
            const old = next[idx];
            next[idx] = { 
                ...old, 
                status: ReconciliationStatus.UNIDENTIFIED, 
                church: PLACEHOLDER_CHURCH, 
                contributor: null, 
                matchMethod: undefined, 
                similarity: 0,
                contributorAmount: undefined
            };
            if (old.contributor?._internalId) {
                const gId = `ghost-${old.contributor._internalId}`;
                if (!next.some(r => r.transaction.id === gId)) {
                    next.push({
                        transaction: { 
                            id: gId, 
                            date: old.contributor.date || new Date().toISOString().split('T')[0], 
                            description: old.contributor.name, 
                            rawDescription: old.contributor.name, 
                            amount: 0, 
                            cleanedDescription: old.contributor.cleanedName || old.contributor.name, 
                            contributionType: old.contributor.contributionType, 
                            originalAmount: old.contributor.originalAmount || "0.00" 
                        },
                        contributor: old.contributor, 
                        status: ReconciliationStatus.PENDING, 
                        church: old.church, 
                        matchMethod: undefined, 
                        similarity: 0, 
                        contributorAmount: old.contributor.amount 
                    });
                }
            }
            regenerateReportPreview(next);
            return next;
        });
    }, [regenerateReportPreview]);

    const resetReconciliation = useCallback(async () => {
        setMatchResults([]);
        setReportPreviewData(null);
        setActiveReportId(null);
        setHasActiveSession(false);
        setBankStatementFile([]);
        setContributorFiles([]);
        setSelectedBankIds([]);
        await clearRemoteList();
        showToast("Sistema resetado.", "success");
        setActiveView('upload');
    }, [clearRemoteList, showToast, setActiveView]);

    const handleAnalyze = useCallback(async (tx: Transaction, contributors: Contributor[]) => {
        setUiFeedback(prev => ({ ...prev, loadingAiId: tx.id }));
        try {
            const name = await getAISuggestion(tx, contributors);
            setUiFeedback(prev => ({ ...prev, aiSuggestion: { id: tx.id, name }, loadingAiId: null }));
        } catch (e) {
            setUiFeedback(prev => ({ ...prev, loadingAiId: null }));
        }
    }, []);

    return {
        activeBankFiles, contributorFiles, matchResults, reportPreviewData,
        activeReportId, setActiveReportId, hasActiveSession, setHasActiveSession,
        comparisonType, setComparisonType, selectedBankIds,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        importGmailTransactions,
        ...uiFeedback,
        setUiFeedback,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile,
        removeContributorFile, toggleBankSelection, handleCompare, resetReconciliation,
        revertMatch, updateReportData, handleAnalyze, setMatchResults, setReportPreviewData,
        setBankStatementFile,
        closeManualIdentify: () => {
            setManualIdentificationTx(null);
            setBulkIdentificationTxs([]);
        },
        findMatchResult: (id: string) => matchResults.find(r => r.transaction.id === id),
        removeTransaction: (id: string) => {
            setMatchResults(prev => {
                const next = prev.filter(r => r.transaction.id !== id);
                regenerateReportPreview(next);
                return next;
            });
        }
    };
};

import { supabase } from './supabaseClient';
import { FileModel } from '../types';
import { Logger } from './monitoringService';
import { get, set } from 'idb-keyval';

const PERSISTENT_STORAGE_KEY = 'identificapix-models-storage-v11';

const getConsolidatedLocalModels = async (): Promise<FileModel[]> => {
    try {
        const currentModels = await get(PERSISTENT_STORAGE_KEY);
        return Array.isArray(currentModels) ? currentModels : [];
    } catch (e) { 
        return []; 
    }
};

const mapDbRowToModel = (row: any): FileModel => {
    // FUNÇÃO CRÍTICA: Garante que dados complexos (JSON) sejam sempre objetos utilizáveis
    const parseJson = (val: any) => {
        if (typeof val === 'string') {
            try { return JSON.parse(val); } catch (e) { return val; }
        }
        return val;
    };

    return {
        id: row.id,
        name: row.name,
        user_id: row.user_id,
        version: row.version || 1,
        lineage_id: row.lineage_id || row.id,
        is_active: row.is_active,
        status: row.status || 'draft',
        fingerprint: parseJson(row.fingerprint),
        mapping: parseJson(row.mapping),
        parsingRules: row.parsing_rules ? parseJson(row.parsing_rules) : { ignoredKeywords: [], rowFilters: [] },
        snippet: row.snippet,
        createdAt: row.created_at || new Date().toISOString(),
        lastUsedAt: row.last_used_at
    };
};

export const modelService = {
    saveModel: async (model: Omit<FileModel, 'id' | 'createdAt'>): Promise<FileModel | null> => {
        try {
            // 1. Desativa versões antigas da mesma linhagem para evitar conflito de DNA
            if (model.lineage_id) {
                await supabase.from('file_models')
                    .update({ is_active: false })
                    .eq('lineage_id', model.lineage_id);
            }

            // 2. PAYLOAD LIMPO (Snake_case rigoroso para o Supabase)
            const dbPayload = {
                name: model.name,
                user_id: model.user_id,
                version: model.version || 1,
                lineage_id: model.lineage_id,
                is_active: true,
                status: model.status || 'approved', // Força aprovado se veio do Laboratório
                fingerprint: model.fingerprint,
                mapping: model.mapping,
                parsing_rules: model.parsingRules || { ignoredKeywords: [], rowFilters: [] },
                snippet: model.snippet || null
            };

            const { data, error } = await supabase
                .from('file_models')
                .insert([dbPayload])
                .select()
                .single();

            if (error) throw error;

            const savedModel = mapDbRowToModel(data);

            // 3. Atualiza cache local imediatamente para persistência instantânea
            const currentLocals = await getConsolidatedLocalModels();
            const updatedLocals = [savedModel, ...currentLocals.filter(m => m.lineage_id !== model.lineage_id)];
            await set(PERSISTENT_STORAGE_KEY, updatedLocals);

            return savedModel;

        } catch (error: any) {
            Logger.error("Erro ao persistir modelo no Supabase", error);
            return null;
        }
    },

    getUserModels: async (userId: string): Promise<FileModel[]> => {
        let remoteModels: FileModel[] = [];
        try {
            // Busca modelos ativos (DNA Global + DNA Usuário)
            const { data, error } = await supabase
                .from('file_models')
                .select('*')
                .eq('is_active', true);

            if (data) {
                remoteModels = data.map(mapDbRowToModel);
            }
        } catch (e) {
            console.error("Falha ao ler modelos remotos", e);
        }

        const localModels = await getConsolidatedLocalModels();
        const uniqueModels = new Map<string, FileModel>();

        // Prioriza sempre a versão mais recente por lineage_id
        [...remoteModels, ...localModels].forEach(m => {
            const existing = uniqueModels.get(m.lineage_id);
            if (!existing || new Date(m.createdAt) > new Date(existing.createdAt)) {
                uniqueModels.set(m.lineage_id, m);
            }
        });

        return Array.from(uniqueModels.values());
    },

    deleteModel: async (id: string) => {
        const { error } = await supabase.from('file_models').delete().eq('id', id);
        return !error;
    },

    getAllModelsAdmin: async (): Promise<FileModel[]> => {
        const { data, error } = await supabase
            .from('file_models')
            .select('*')
            .order('created_at', { ascending: false });

        if (error) return [];
        return data.map(mapDbRowToModel);
    },

    updateModelName: async (id: string, name: string) => {
        const { error } = await supabase.from('file_models').update({ name }).eq('id', id);
        return !error;
    }
};

import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';
import { extractTransactionsFromComplexBlock } from '../services/geminiService';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

/**
 * DATABASE MODEL STRATEGY (V11 - PERSISTÊNCIA ABSOLUTA)
 */
export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
                (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
                (m.fingerprint.dataTopology === fileFp.dataTopology)
            )
        );
    },
    parse: async (content, yearAnchor, models, globalKeywords = []) => {
        if (!models || models.length === 0) return [];

        const fileFp = Fingerprinter.generate(content);
        const matchingModel = models.find(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp?.headerHash) || 
                (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                (m.fingerprint.dataTopology === fileFp?.dataTopology)
            )
        );

        if (!matchingModel) {
            console.warn("[Strategy] Nenhum modelo ativo compatível com o DNA do arquivo.");
            return [];
        }

        // Modo Inteligência de Bloco (IA Contextual)
        const extractionMode = (matchingModel.mapping as any).extractionMode;
        if (extractionMode === 'BLOCK') {
            const results = await extractTransactionsFromComplexBlock(content);
            return results.map((t, i) => ({
                id: `db-block-${matchingModel.id}-${i}-${Date.now()}`,
                date: t.date,
                description: t.description,
                rawDescription: t.description,
                paymentMethod: t.paymentMethod || 'OUTROS',
                amount: t.amount,
                originalAmount: String(t.amount),
                cleanedDescription: t.description, 
                contributionType: t.type || 'AUTO'
            }));
        }

        // Modo Tradicional (Colunas Fixas Aprendidas)
        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);

        // RECUPERAÇÃO DAS COLUNAS APRENDIDAS
        const { 
            dateColumnIndex, 
            descriptionColumnIndex, 
            amountColumnIndex, 
            paymentMethodColumnIndex,
            typeColumnIndex, 
            skipRowsStart 
        } = matchingModel.mapping;

        // REGRA DE OURO: Para modelos aprendidos em PDFs/Textos normalizados, o delimitador é SEMPRE ';'
        // Isso garante que o motor encontre a "Coluna 1" mesmo que no arquivo original fosse espaços.
        const delimiter = (content.includes(';') || matchingModel.fingerprint.delimiter === ';') ? ';' : matchingModel.fingerprint.delimiter;

        lines.forEach((line, index) => {
            // Pula cabeçalhos conforme treinado
            if (index < (skipRowsStart || 0)) return;

            const cols = line.split(delimiter);

            // Verifica se a linha tem colunas suficientes para o mapeamento aprendido
            if (cols.length > Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) {
                const rawDate = (cols[dateColumnIndex] || '').trim();
                const rawDesc = (cols[descriptionColumnIndex] || '').trim();
                const rawAmount = (cols[amountColumnIndex] || '').trim();

                if (!rawDate && !rawDesc && !rawAmount) return;

                const rawForm = (paymentMethodColumnIndex !== undefined && paymentMethodColumnIndex !== -1 && cols[paymentMethodColumnIndex])
                    ? cols[paymentMethodColumnIndex].trim().toUpperCase()
                    : TypeResolver.resolveFromDescription(rawDesc);

                const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                const standardizedAmount = AmountResolver.clean(rawAmount);
                const numericValue = parseFloat(standardizedAmount);

                // Validação básica de transação real (evita linhas vazias ou ruídos)
                if (rawDesc.length > 1 && !isNaN(numericValue)) {
                    transactions.push({
                        id: `dbmodel-${matchingModel.id}-${index}-${Date.now()}`,
                        date: isoDate || (rawDate ? `ERR:${rawDate}` : new Date().toISOString().split('T')[0]),
                        description: rawDesc,
                        rawDescription: rawDesc,
                        paymentMethod: rawForm,
                        amount: numericValue,
                        originalAmount: rawAmount,
                        cleanedDescription: rawDesc, 
                        contributionType: (typeColumnIndex !== undefined && typeColumnIndex !== -1 && cols[typeColumnIndex]) 
                            ? cols[typeColumnIndex].trim().toUpperCase() 
                            : TypeResolver.resolveFromDescription(rawDesc)
                    });
                }
            }
        });

        return transactions;
    }
};

/**
 * GENERIC STRATEGY (Fallback)
 */
export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords) => {
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return [];

        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));

        const dIdx = DateResolver.identifyDateColumn(rows);
        const aIdx = AmountResolver.identifyAmountColumn(rows, [dIdx]);
        const nIdx = NameResolver.identifyNameColumn(rows, [dIdx, aIdx]);

        if (dIdx === -1 || aIdx === -1) return [];

        return rows.map((row, i) => {
            const date = DateResolver.resolveToISO(row[dIdx], yearAnchor);
            const amountStr = AmountResolver.clean(row[aIdx]);
            const amount = parseFloat(amountStr);

            if (!date || isNaN(amount) || amount === 0) return null;

            const rawDesc = row[nIdx] || 'S/D';
            return {
                id: `gen-${i}-${Date.now()}`, 
                date, 
                amount,
                description: rawDesc, 
                rawDescription: rawDesc,
                originalAmount: row[aIdx], 
                paymentMethod: TypeResolver.resolveFromDescription(rawDesc),
                cleanedDescription: NameResolver.clean(rawDesc, globalKeywords),
                contributionType: TypeResolver.resolveFromDescription(rawDesc)
            } as Transaction;
        }).filter((t): t is Transaction => t !== null);
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<{ transactions: Transaction[], strategyName: string }> => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        let targetModel = overrideModel;
        if (!targetModel) {
            const fileFp = Fingerprinter.generate(content);
            targetModel = models.find(m => 
                m.is_active && (
                    (m.fingerprint.headerHash === fileFp?.headerHash && m.fingerprint.headerHash !== null) ||
                    (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                    (m.fingerprint.dataTopology === fileFp?.dataTopology)
                )
            );
        }

        if (targetModel) {
            const result = await DatabaseModelStrategy.parse(content, yearAnchor, [targetModel], globalKeywords);
            return { transactions: result as Transaction[], strategyName: targetModel.name };
        }

        const genResult = GenericStrategy.parse(content, yearAnchor, models, globalKeywords) as Transaction[];
        return { transactions: genResult, strategyName: 'Genérico' };
    }
};

import { CanonicalDocumentNormalizer } from './CanonicalDocumentNormalizer';

/**
 * SERVIÇO DE DOMÍNIO: FINGERPRINTER (V4 - ULTRA CONSISTENTE)
 * --------------------------------------------------------------------------
 * Gera a identidade estrutural (DNA) de qualquer conteúdo tabular.
 */

export interface StructuralFingerprint {
    columnCount: number;
    delimiter: string;
    headerHash: string | null;
    dataTopology: string;
    canonicalSignature?: string;
    structuralPattern?: string;
}

export const Fingerprinter = {
    /**
     * Detecta o delimitador de forma estatística.
     */
    detectDelimiter: (line: string): string => {
        if (!line) return ';';
        const candidates = [';', ',', '\t', '|'];
        const counts = candidates.map(char => ({ 
            char, 
            count: line.split(char).length - 1 
        }));
        counts.sort((a, b) => b.count - a.count);
        return counts[0].count > 0 ? counts[0].char : ';';
    },

    /**
     * Gera o DNA estrutural para reconhecimento independente de formato.
     */
    generate: (content: string): StructuralFingerprint | null => {
        if (!content || typeof content !== 'string') return null;

        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return null;

        const firstLine = lines[0];
        const delimiter = Fingerprinter.detectDelimiter(firstLine);
        const cells = firstLine.split(delimiter);

        // 1. HASH DE CABEÇALHO ULTRA-LIMPO (Crucial para match)
        // Remove absolutamente tudo que não for letra ou número para evitar falha por espaços
        const cleanHeader = firstLine
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '') 
            .replace(/[^A-Z0-9]/gi, '')      
            .toUpperCase();

        // Gerador de hash simples e estável
        let hash = 0;
        for (let i = 0; i < cleanHeader.length; i++) {
            const char = cleanHeader.charCodeAt(i);
            hash = ((hash << 5) - hash) + char;
            hash = hash & hash;
        }
        const headerHash = Math.abs(hash).toString(36);

        // 2. ASSINATURA CANÔNICA
        const canonicalSignature = CanonicalDocumentNormalizer.generateSignature(lines);
        const structuralPattern = CanonicalDocumentNormalizer.generateStructuralPattern(lines);

        // 3. TOPOLOGIA DE DADOS (DNA de Tipos)
        const dataRows = lines.slice(1, 10);
        const representativeRow = dataRows.find(r => r.split(delimiter).length >= 2) || firstLine;

        const topologyString = representativeRow.split(delimiter).map(c => {
            const val = c.trim().replace(/[R$\s]/g, '').replace(',', '.');
            if (/^\d{1,4}[/-]\d{1,2}/.test(val)) return 'D'; 
            if (!isNaN(parseFloat(val)) && /\d/.test(val)) return 'N';
            if (val.length === 0) return 'E';
            return 'S';
        }).join('');

        return { 
            columnCount: cells.length, 
            delimiter, 
            headerHash, 
            dataTopology: topologyString,
            canonicalSignature,
            structuralPattern
        };
    }
};

import React, { useState, useMemo, useContext, useCallback, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { useUI } from '../../contexts/UIContext';
import { AppContext } from '../../contexts/AppContext'; 
import { useAuth } from '../../contexts/AuthContext';
import { modelService } from '../../services/modelService';
import { FileModel, Transaction } from '../../types';
import { CloudArrowUpIcon, DocumentArrowDownIcon, SparklesIcon, TableCellsIcon, ShieldCheckIcon, BrainIcon } from '../Icons';

// Sub-componentes
import { SpreadsheetRenderer } from './preprocessor/SpreadsheetRenderer';
import { PDFRenderer } from './preprocessor/PDFRenderer';
import { SimulatedResultsTable } from './preprocessor/SimulatedResultsTable';
import { MappingControls } from './preprocessor/MappingControls';
import { TeachingBanner } from './preprocessor/TeachingBanner';
import { PreprocessorHeader } from './preprocessor/PreprocessorHeader';

// Hooks
import { useFileProcessing } from '../../hooks/useFileProcessing';
import { useSimulation } from '../../hooks/useSimulation';
import { useAIPatternTeacher } from '../../hooks/useAIPatternTeacher';
import { FileUploader } from '../FileUploader';

export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel; 
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
    mode?: 'create' | 'test' | 'refine'; 
}> = ({ onClose, initialFile, initialModel, onSuccess, mode = 'create' }) => {
    const { showToast } = useUI();
    const { user } = useAuth(); 
    const { effectiveIgnoreKeywords, contributionKeywords, fetchModels } = useContext(AppContext);

    // Estado para o arquivo sendo trabalhado
    const [uploadedFile, setUploadedFile] = useState<{ content: string, fileName: string, rawFile?: File } | null>(null);

    // Efeito para carregar dados do modelo existente se estiver em modo Reaprender
    useEffect(() => {
        if (mode === 'refine' && initialModel && !uploadedFile && !initialFile) {
            setUploadedFile({
                content: initialModel.snippet || "",
                fileName: initialModel.name,
                rawFile: undefined
            });
        }
    }, [mode, initialModel, uploadedFile, initialFile]);

    const activeFile = initialFile || uploadedFile || null;

    const isPdf = useMemo(() => /\.pdf$/i.test(activeFile?.fileName || ''), [activeFile]);
    const cleaningKeywords = useMemo(() => [...effectiveIgnoreKeywords, ...contributionKeywords], [effectiveIgnoreKeywords, contributionKeywords]);

    const { 
        gridData, setGridData, isGridLoading,
        activeMapping, setActiveMapping, detectedFingerprint 
    } = useFileProcessing({ activeFile, initialModel, isPdf });

    const {
        processedTransactions, editingRowIndex, editingRowData, 
        setEditingRowData, startEdit, saveRow, cancelEdit, runSimulation
    } = useSimulation({ gridData, activeMapping, cleaningKeywords });

    const {
        isInferringMapping, learnedPatternSource, setLearnedPatternSource, handleApplyCorrectionPattern
    } = useAIPatternTeacher({ gridData, setGridData, setActiveMapping, showToast });

    const [isSavingModel, setIsSavingModel] = useState(false);
    const [showNameModal, setShowNameModal] = useState(false);
    const [pendingAction, setPendingAction] = useState<'draft' | 'approved'>('draft');
    const [modelName, setModelName] = useState(initialModel?.name || '');

    const handlePersistModel = useCallback(async (approvalStatus: 'draft' | 'approved', finalName: string) => {
        if (!activeMapping || !detectedFingerprint || !user) return;

        setIsSavingModel(true);
        try {
            // Salva o conteúdo atual como snippet para futuras edições (Reaprender)
            const finalSnippet = gridData.slice(0, 100).map(row => row.join(';')).join('\n');

            const modelData: any = { 
                name: finalName, 
                user_id: user.id, 
                version: initialModel ? initialModel.version + 1 : 1, 
                lineage_id: initialModel ? initialModel.lineage_id : `mod-${Date.now()}`, 
                is_active: true, 
                fingerprint: {
                    ...detectedFingerprint,
                    delimiter: detectedFingerprint.delimiter || ';'
                }, 
                mapping: activeMapping, 
                parsingRules: { ignoredKeywords: [], rowFilters: [] }, 
                snippet: finalSnippet, 
                status: approvalStatus 
            };

            const saved = await modelService.saveModel(modelData);
            if (saved) {
                showToast(approvalStatus === 'approved' ? "Modelo certificado e salvo!" : "Rascunho salvo.", "success");
                if (fetchModels) await fetchModels();
                if (onSuccess) onSuccess(saved as FileModel, []);
                onClose();
            } else {
                throw new Error("Falha na persistência");
            }
        } catch (e: any) { 
            showToast("Erro ao salvar padrão no servidor.", "error"); 
        } finally { setIsSavingModel(false); }
    }, [activeMapping, detectedFingerprint, user, gridData, initialModel, onSuccess, onClose, showToast, fetchModels]);

    return createPortal(
        <div className="fixed inset-0 z-[9999] bg-[#050B14]/90 backdrop-blur-md flex items-center justify-center p-2 sm:p-4 animate-fade-in overflow-hidden">
            <div className="bg-white dark:bg-[#0F172A] w-full max-w-[1600px] h-full max-h-[95dvh] rounded-[2.5rem] shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in relative">

                <PreprocessorHeader 
                    fileName={activeFile?.fileName || 'Laboratório de IA'} 
                    canApprove={processedTransactions.length > 0} 
                    onApprove={() => { setPendingAction('approved'); setShowNameModal(true); }}
                    onClose={onClose}
