import { useState, useCallback, useEffect, useMemo } from 'react';
import { supabase } from '../services/supabaseClient';
import { Bank, Church, ChurchFormData, LearnedAssociation, MatchResult, FileModel } from '../types';
import { usePersistentState } from './usePersistentState';
import { Logger } from '../services/monitoringService';
import { normalizeString, DEFAULT_CONTRIBUTION_KEYWORDS } from '../services/processingService';
import { useAuth } from '../contexts/AuthContext';
import { modelService } from '../services/modelService';

const DEFAULT_IGNORE_KEYWORDS = [
    'DÍZIMOS', 'OFERTAS', 'MISSÕES', 'TERRENO - NOVA SEDE', 'PIX', 'TED', 'DOC',
    'Transferência', 'Pagamento', 'Recebimento', 'Depósito', 'Contribuição',
    'Sr', 'Sra', 'Dr', 'Dra', 'RECEB OUTRA IF'
];

export const useReferenceData = (user: any | null, showToast: (msg: string, type: 'success' | 'error') => void) => {
    const { subscription } = useAuth();
    const userSuffix = user ? `-${user.id}` : '-guest';

    // --- State ---
    const [banks, setBanks] = usePersistentState<Bank[]>(`identificapix-banks${userSuffix}`, []);
    const [churches, setChurches] = usePersistentState<Church[]>(`identificapix-churches${userSuffix}`, []);
    const [fileModels, setFileModels] = useState<FileModel[]>([]);
    const [similarityLevel, setSimilarityLevel] = usePersistentState<number>(`identificapix-similarity${userSuffix}`, 55);
    const [dayTolerance, setDayTolerance] = usePersistentState<number>(`identificapix-daytolerance${userSuffix}`, 2);

    const [customIgnoreKeywords, setCustomIgnoreKeywords] = usePersistentState<string[]>(`identificapix-ignore-keywords${userSuffix}`, DEFAULT_IGNORE_KEYWORDS);
    const [contributionKeywords, setContributionKeywords] = usePersistentState<string[]>(`identificapix-contribution-types${userSuffix}`, DEFAULT_CONTRIBUTION_KEYWORDS);

    const [learnedAssociations, setLearnedAssociations] = useState<LearnedAssociation[]>([]);

    const [editingBank, setEditingBank] = useState<Bank | null>(null);
    const [editingChurch, setEditingChurch] = useState<Church | null>(null);

    // --- Methods for Keywords ---
    const addIgnoreKeyword = useCallback((k: string) => {
        if (!k.trim()) return;
        setCustomIgnoreKeywords(prev => prev.includes(k.trim()) ? prev : [...prev, k.trim()]);
    }, [setCustomIgnoreKeywords]);

    const removeIgnoreKeyword = useCallback((k: string) => setCustomIgnoreKeywords(prev => prev.filter(i => i !== k)), [setCustomIgnoreKeywords]);

    const addContributionKeyword = useCallback((k: string) => {
        if (!k.trim()) return;
        setContributionKeywords(prev => {
            const normalized = k.toUpperCase().trim();
            return prev.includes(normalized) ? prev : [...prev, normalized];
        });
    }, [setContributionKeywords]);

    const removeContributionKeyword = useCallback((k: string) => setContributionKeywords(prev => prev.filter(i => i !== k)), [setContributionKeywords]);

    // --- Sincronização de Dados ---
    useEffect(() => {
        if (!user) return;

        const syncData = async () => {
            try {
                const { data: banksData } = await supabase.from('banks').select('*').eq('user_id', user.id);
                if (banksData) setBanks(prev => banksData.length > 0 ? banksData : prev);

                const { data: churchesData } = await supabase.from('churches').select('*').eq('user_id', user.id);
                if (churchesData) setChurches(prev => churchesData.length > 0 ? churchesData : prev);
            } catch (e) {
                console.error("Erro ao sincronizar cadastros:", e);
            }
        };

        syncData();
    }, [user, setBanks, setChurches]);

    const fetchModels = useCallback(async () => {
        if (!user) return;
        try {
            const models = await modelService.getUserModels(user.id);
            setFileModels(models);
        } catch (e) { console.error(e); }
    }, [user]);

    useEffect(() => { fetchModels(); }, [fetchModels]);

    const openEditBank = useCallback((bank: Bank) => setEditingBank(bank), []);
    const closeEditBank = useCallback(() => setEditingBank(null), []);

    const updateBank = useCallback(async (bankId: string, name: string) => {
        if(!user) return;
        setBanks(prev => prev.map(b => b.id === bankId ? { ...b, name } : b));
        closeEditBank();
        await supabase.from('banks').update({ name }).eq('id', bankId);
        showToast('Banco atualizado.', 'success');
    }, [user, banks, setBanks, closeEditBank, showToast]);

    const addBank = useCallback(async (name: string): Promise<boolean> => {
        if(!user) return false;
        if (banks.length >= (subscription.maxBanks || 1)) {
            showToast(`Limite atingido (${subscription.maxBanks}).`, 'error');
            return false;
        }
        const { data, error } = await supabase.from('banks').insert([{ name, user_id: user.id }]).select();
        if (data) {
            setBanks(prev => [...prev, data[0]]);
            showToast('Banco adicionado.', 'success');
            return true;
        }
        return false;
    }, [user, setBanks, showToast, banks.length, subscription.maxBanks]);

    const openEditChurch = useCallback((church: Church) => setEditingChurch(church), []);
    const closeEditChurch = useCallback(() => setEditingChurch(null), []);

    const updateChurch = useCallback(async (churchId: string, formData: ChurchFormData) => {
        if(!user) return;
        setChurches(prev => prev.map(c => c.id === churchId ? { ...c, ...formData } : c));
        closeEditChurch();
        await supabase.from('churches').update(formData).eq('id', churchId);
        showToast('Igreja atualizada.', 'success');
    }, [user, churches, setChurches, closeEditChurch, showToast]);

    const addChurch = useCallback(async (formData: ChurchFormData): Promise<boolean> => {
        if(!user) return false;
        if (churches.length >= (subscription.maxChurches || 1)) {
            showToast(`Limite atingido (${subscription.maxChurches}).`, 'error');
            return false;
        }
        const { data } = await supabase.from('churches').insert([{ ...formData, user_id: user.id }]).select();
        if (data) {
            setChurches(prev => [...prev, data[0]]);
            showToast('Igreja adicionada.', 'success');
            return true;
        }
        return false;
    }, [user, setChurches, showToast, churches.length, subscription.maxChurches]);

    // --- LÓGICA DE APRENDIZADO REFINADA ---
    useEffect(() => {
        if (!user) return;
        const fetchAssociations = async () => {
            const { data } = await supabase.from('learned_associations').select('*').eq('user_id', user.id);
            if (data) {
                setLearnedAssociations(data.map(d => ({
                    id: d.id, normalizedDescription: d.normalized_description,
                    contributorNormalizedName: d.contributor_normalized_name,
                    churchId: d.church_id, user_id: d.user_id
                })));
            }
        };
        fetchAssociations();
    }, [user]);

    const learnAssociation = useCallback(async (matchResult: MatchResult) => {
        if (!user || !matchResult.contributor || !matchResult.church) return;

        const normalizedDesc = normalizeString(matchResult.transaction.description, customIgnoreKeywords);
        const normalizedContrib = matchResult.contributor.normalizedName || normalizeString(matchResult.contributor.name, customIgnoreKeywords);

        const existingIdx = learnedAssociations.findIndex(la => la.normalizedDescription === normalizedDesc);
        const existing = existingIdx !== -1 ? learnedAssociations[existingIdx] : null;

        if (existing && existing.contributorNormalizedName === normalizedContrib && existing.churchId === matchResult.church.id) {
            return;
        }

        const newAssociation: LearnedAssociation = { 
            normalizedDescription: normalizedDesc, 
            contributorNormalizedName: normalizedContrib, 
            churchId: matchResult.church.id, 
            user_id: user.id 
        };

        try {
            if (existing) {
                setLearnedAssociations(prev => {
                    const next = [...prev];
                    next[existingIdx] = newAssociation;
                    return next;
                });

                await supabase.from('learned_associations')
                    .update({ 
                        contributor_normalized_name: normalizedContrib, 
                        church_id: matchResult.church.id 
                    })
                    .eq('normalized_description', normalizedDesc)
                    .eq('user_id', user.id);
            } else {
                setLearnedAssociations(prev => [...prev, newAssociation]);
                await supabase.from('learned_associations').insert({ 
                    user_id: user.id, 
                    normalized_description: normalizedDesc, 
                    contributor_normalized_name: normalizedContrib, 
                    church_id: matchResult.church.id 
                });
            }
        } catch (err) {
            console.error("Erro ao persistir aprendizado da IA:", err);
        }
    }, [user, customIgnoreKeywords, learnedAssociations]);

    return useMemo(() => ({
        banks, setBanks, churches, setChurches, fileModels, fetchModels, similarityLevel, setSimilarityLevel, dayTolerance, setDayTolerance,
        customIgnoreKeywords, setCustomIgnoreKeywords, addIgnoreKeyword, removeIgnoreKeyword,
        contributionKeywords, setContributionKeywords, addContributionKeyword, removeContributionKeyword,
        learnedAssociations, setLearnedAssociations, learnAssociation,
        editingBank, openEditBank, closeEditBank, updateBank, addBank,
        editingChurch, openEditChurch, closeEditChurch, updateChurch, addChurch
    }), [banks, churches, fileModels, fetchModels, similarityLevel, dayTolerance, customIgnoreKeywords, contributionKeywords, learnedAssociations, editingBank, editingChurch, setBanks, setChurches, setSimilarityLevel, setDayTolerance, setCustomIgnoreKeywords, setContributionKeywords, addIgnoreKeyword, removeIgnoreKeyword, addContributionKeyword, removeContributionKeyword, setLearnedAssociations, learnAssociation, openEditBank, closeEditBank, updateBank, addBank, openEditChurch, closeEditChurch, updateChurch, addChurch]);
};

import { FileProbe } from './Probe';
import { FileType, NormalizedTransaction } from '../types/core-engine';
import { ExcelAdapter } from '../adapters/ExcelAdapter';
import { CSVParser } from '../parsers/CSVParser';
import { Normalizer } from './Normalizer';
import { StrategyEngine } from '../strategies';

/**
 * Cérebro do Core Engine v4 (FIDELIDADE ABSOLUTA AO LABORATÓRIO).
 * Orquestra o fluxo de dados do arquivo bruto até a saída normalizada.
 */
export class Orchestrator {

  /**
   * Processa um arquivo financeiro e retorna dados em 3 colunas.
   */
  static async processFile(file: File, models: any[] = [], keywords: string[] = []): Promise<any> {
    // 1. Identificação (Probe)
    const probe = await FileProbe.identify(file);
    let content = "";

    // 2. Extração de Texto / Normalização de Colunas Virtuais (CRÍTICO PARA PDF)
    if (probe.type === FileType.PDF || probe.type === FileType.TXT) {
        const rawText = await file.text();
        // REGRA DE OURO: Paridade com useFileProcessing.ts do Laboratório
        // Transforma 2 ou mais espaços em ponto e vírgula para criar colunas virtuais
        content = rawText
            .split(/\r?\n/)
            .map(line => {
                const trimmed = line.trim();
                if (!trimmed) return "";
                if (!trimmed.includes(';') && !trimmed.includes('\t')) {
                    return trimmed.replace(/\s{2,}/g, ';');
                }
                return trimmed;
            })
            .filter(line => line.length > 0)
            .join('\n');
    } else {
        // Para Excel, o adapter já resolve
        const adapter = new ExcelAdapter();
        const rawDoc = await adapter.readRaw(file);
        content = rawDoc.content.map(row => row.join(';')).join('\n');
    }

    // 3. Aplicação da Estratégia de Modelo Aprendido
    // Passamos o conteúdo já com as "Colunas Virtuais" (;) para o motor
    const result = await StrategyEngine.process(file.name, content, models, keywords);

    return result;
  }
}

import { Transaction, FileModel } from '../types';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { NameResolver } from './processors/NameResolver';
import { TypeResolver } from './processors/TypeResolver';
import { Fingerprinter } from './processors/Fingerprinter';
import { extractTransactionsFromComplexBlock } from '../services/geminiService';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

/**
 * DATABASE MODEL STRATEGY (V12 - SINCRONIA TOTAL)
 */
export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
                (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
                (m.fingerprint.dataTopology === fileFp.dataTopology)
            )
        );
    },
    parse: async (content, yearAnchor, models, globalKeywords = []) => {
        if (!models || models.length === 0) return [];

        const fileFp = Fingerprinter.generate(content);
        const matchingModel = models.find(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp?.headerHash) || 
                (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                (m.fingerprint.dataTopology === fileFp?.dataTopology)
            )
        );

        if (!matchingModel) return [];

        // MODO 1: EXTRAÇÃO DE BLOCO
        const extractionMode = (matchingModel.mapping as any).extractionMode;
        if (extractionMode === 'BLOCK') {
            const results = await extractTransactionsFromComplexBlock(content);
            return results.map((t, i) => ({
                id: `db-block-${matchingModel.id}-${i}-${Date.now()}`,
                date: t.date,
                description: t.description,
                rawDescription: t.description,
                paymentMethod: t.paymentMethod || 'OUTROS',
                amount: t.amount,
                originalAmount: String(t.amount),
                cleanedDescription: t.description, 
                contributionType: t.type || 'AUTO'
            }));
        }

        // MODO 2: COLUNAS FIXAS (MAIS COMUM)
        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = matchingModel.mapping;
        const paymentMethodColumnIndex = matchingModel.mapping.paymentMethodColumnIndex;

        // FORÇA O DELIMITADOR DE COLUNAS VIRTUAIS (;) PARA PARIDADE COM LABORATÓRIO
        const delimiter = content.includes(';') ? ';' : (matchingModel.fingerprint.delimiter || ';');

        lines.forEach((line, index) => {
            if (index < (skipRowsStart || 0)) return;
            const cols = line.split(delimiter);

            if (cols.length > Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) {
                const rawDate = (cols[dateColumnIndex] || '').trim();
                const rawDesc = (cols[descriptionColumnIndex] || '').trim();
                const rawAmount = (cols[amountColumnIndex] || '').trim();

                if (!rawDate && !rawDesc && !rawAmount) return;

                const rawForm = (paymentMethodColumnIndex !== undefined && paymentMethodColumnIndex !== -1 && cols[paymentMethodColumnIndex])
                    ? cols[paymentMethodColumnIndex].trim().toUpperCase()
                    : TypeResolver.resolveFromDescription(rawDesc);

                const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                const standardizedAmount = AmountResolver.clean(rawAmount);
                const numericValue = parseFloat(standardizedAmount);

                if (rawDesc.length > 1 && !isNaN(numericValue)) {
                    transactions.push({
                        id: `dbmodel-${matchingModel.id}-${index}-${Date.now()}`,
                        date: isoDate || (rawDate ? `ERR:${rawDate}` : new Date().toISOString().split('T')[0]),
                        description: rawDesc,
                        rawDescription: rawDesc,
                        paymentMethod: rawForm,
                        amount: numericValue,
                        originalAmount: rawAmount,
                        cleanedDescription: rawDesc, 
                        contributionType: (typeColumnIndex !== undefined && typeColumnIndex !== -1 && cols[typeColumnIndex]) 
                            ? cols[typeColumnIndex].trim().toUpperCase() 
                            : TypeResolver.resolveFromDescription(rawDesc)
                    });
                }
            }
        });

        return transactions;
    }
};

/**
 * GENERIC STRATEGY (Fallback)
 */
export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords) => {
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return [];

        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const rows = lines.map(l => l.split(delimiter));

        const dIdx = DateResolver.identifyDateColumn(rows);
        const aIdx = AmountResolver.identifyAmountColumn(rows, [dIdx]);
        const nIdx = NameResolver.identifyNameColumn(rows, [dIdx, aIdx]);

        if (dIdx === -1 || aIdx === -1) return [];

        return rows.map((row, i) => {
            const date = DateResolver.resolveToISO(row[dIdx], yearAnchor);
            const amountStr = AmountResolver.clean(row[aIdx]);
            const amount = parseFloat(amountStr);

            if (!date || isNaN(amount) || amount === 0) return null;

            const rawDesc = row[nIdx] || 'S/D';
            return {
                id: `gen-${i}-${Date.now()}`, 
                date, 
                amount,
                description: rawDesc, 
                rawDescription: rawDesc,
                originalAmount: row[aIdx], 
                paymentMethod: TypeResolver.resolveFromDescription(rawDesc),
                cleanedDescription: NameResolver.clean(rawDesc, globalKeywords),
                contributionType: TypeResolver.resolveFromDescription(rawDesc)
            } as Transaction;
        }).filter((t): t is Transaction => t !== null);
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<{ transactions: Transaction[], strategyName: string }> => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        let targetModel = overrideModel;
        if (!targetModel) {
            const fileFp = Fingerprinter.generate(content);
            targetModel = models.find(m => 
                m.is_active && (
                    (m.fingerprint.headerHash === fileFp?.headerHash && m.fingerprint.headerHash !== null) ||
                    (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                    (m.fingerprint.dataTopology === fileFp?.dataTopology)
                )
            );
        }

        if (targetModel) {
            const result = await DatabaseModelStrategy.parse(content, yearAnchor, [targetModel], globalKeywords);
            return { transactions: result as Transaction[], strategyName: targetModel.name };
        }

        const genResult = GenericStrategy.parse(content, yearAnchor, models, globalKeywords) as Transaction[];
        return { transactions: genResult, strategyName: 'Genérico' };
    }
};

