        models: FileModel[], 
        globalKeywords: string[]
    ): Promise<any> {
        const fileNameLower = file.name.toLowerCase();
        const isPdf = fileNameLower.endsWith('.pdf');
        const isExcel = fileNameLower.endsWith('.xlsx') || fileNameLower.endsWith('.xls');

        let processedContent = content;

        // REGRA DE OURO: Paridade absoluta com useFileProcessing.ts
        // Se não for Excel e não tiver delimitadores óbvios, tratamos espaços duplos como colunas (;)
        if (!isExcel) {
            const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
            processedContent = lines.map(line => {
                const trimmed = line.trim();
                if (!trimmed) return "";
                // Se a linha não tem ponto e vírgula mas tem espaços duplos, normaliza
                if (!trimmed.includes(';') && !trimmed.includes('\t') && trimmed.includes('  ')) {
                    return trimmed.replace(/\s{2,}/g, ';');
                }
                return trimmed;
            }).join('\n');
        }

        // 2. GERAÇÃO DE DNA (Fingerprint) sobre o conteúdo JÁ NORMALIZADO
        const fingerprint = Fingerprinter.generate(processedContent);

        // 3. ROTEAMENTO DE ESTRATÉGIA
        // Passamos o conteúdo normalizado para o StrategyEngine
        const result = await StrategyEngine.process(file.name, processedContent, models, globalKeywords);

        return {
            source: 'upload',
            transactions: result.transactions,
            strategyUsed: result.strategyName,
            fingerprint: fingerprint || { columnCount: 0 }
        };
    },

    /**
     * Porta 2: Processamento de Dados Virtuais (Gmail / API Sync)
     */
    async processVirtualData(
        sourceName: string,
        data: any[],
        globalKeywords: string[]
    ): Promise<any> {
        const yearAnchor = new Date().getFullYear();

        const transactions: Transaction[] = data.map((item, index) => {
            const rawDesc = item.description || item.memo || 'Sem descrição';
            const rawAmount = String(item.amount);

            const cleanedDesc = NameResolver.clean(rawDesc, globalKeywords);
            const isoDate = DateResolver.resolveToISO(item.date, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);

            return {
                id: `gmail-sync-${Date.now()}-${index}`,
                date: isoDate,
                description: rawDesc.trim(),
                rawDescription: `GMAIL_ORIGIN: ${rawDesc.trim()}`,
                amount: parseFloat(amountStr),
                originalAmount: rawAmount,
                cleanedDescription: cleanedDesc,
                contributionType: item.type || 'PIX'
            };
        }).filter(t => t.date && !isNaN(t.amount));

        return {
            source: 'gmail',
            transactions,
            strategyUsed: 'GATEWAY_IA_GMAIL',
            fingerprint: { is_virtual: true, columnCount: 3 }
        };
    }
};

import { useState, useCallback } from 'react';
import { extractStructuredDataByExample } from '../services/geminiService';
import { FileModel, Transaction } from '../types';

export interface LearningPackage {
    model: Partial<FileModel>;
    sampleTransactions: Transaction[];
    confidence: number;
}

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async (): Promise<LearningPackage | null> => {
        if (!learnedPatternSource || gridData.length === 0) return null;

        setIsInferringMapping(true);
        try {
            const { originalRaw, corrected } = learnedPatternSource;
            const rawSnippet = gridData.slice(0, 300).map(row => row.join(';')).join('\n');

            const userExample = `O usuário corrigiu uma linha manualmente. Aprenda este padrão estrutural:
               LINHA ORIGINAL: [${originalRaw.join(' | ')}] 
               CORREÇÃO DESEJADA: 
               - Data: ${corrected.date}
               - Descrição: ${corrected.cleanedDescription}
               - Valor: ${corrected.amount}
               - Tipo: ${corrected.contributionType}
               - Forma (Pagamento): ${corrected.paymentMethod}

               Instrução: Re-analise o snippet de dados e extraia TODAS as linhas seguindo este padrão de colunas.`;

            const result = await extractStructuredDataByExample(rawSnippet, userExample);

            if (result?.rows?.length > 0) {
                // Criamos uma nova grade com 5 colunas baseada no aprendizado
                const reStructuredGrid = result.rows.map((r: any) => [
                    String(r.date || ''), 
                    String(r.description || ''), 
                    String(r.amount || '0'),
                    String(r.type || 'OUTROS'),
                    String(r.paymentMethod || 'OUTROS')
                ]);

                setGridData(reStructuredGrid);

                // Mapeamento forçado para a nova estrutura de 5 colunas gerada pela IA
                const refinedMapping = { 
                    extractionMode: 'COLUMNS',
                    dateColumnIndex: 0, 
                    descriptionColumnIndex: 1, 
                    amountColumnIndex: 2, 
                    typeColumnIndex: 3, 
                    paymentMethodColumnIndex: 4,
                    skipRowsStart: 0,
                    skipRowsEnd: 0,
                    decimalSeparator: '.' as const,
                    thousandsSeparator: '' as const
                };

                setActiveMapping(refinedMapping);
                setLearnedPatternSource(null); 
                showToast("Inteligência refinada: Forma e Tipo aplicados.", "success");

                return {
                    model: { mapping: refinedMapping },
                    sampleTransactions: [], 
                    confidence: 0.99
                };
            }
            return null;
        } catch (e: any) { 
            showToast("Erro ao processar padrão.", "error"); 
            return null;
        } finally { 
            setIsInferringMapping(false); 
        }
    }, [learnedPatternSource, gridData, setGridData, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

/**
 * ESPECIALISTA EM INTELIGÊNCIA MONETÁRIA (Core Engine v3)
 */
export class AmountResolver {
  static identifyAmountColumn(rows: string[][], excludedIndices: number[] = []): number {
    const sample = rows.slice(0, 100);
    const candidateScores = new Map<number, { count: number, totalMagnitude: number }>();

    sample.forEach(row => {
      row.forEach((cell, index) => {
        if (excludedIndices.includes(index)) return;

        const val = this.simpleParse(cell);
        if (val !== null && val !== 0) {
          const stats = candidateScores.get(index) || { count: 0, totalMagnitude: 0 };
          stats.count++;
          stats.totalMagnitude += Math.abs(val);
          candidateScores.set(index, stats);
        }
      });
    });

    const validCandidates = Array.from(candidateScores.entries())
      .filter(([_, stats]) => stats.count > (sample.length * 0.15));

    if (validCandidates.length === 0) return -1;

    validCandidates.sort((a, b) => {
      const avgA = a[1].totalMagnitude / a[1].count;
      const avgB = b[1].totalMagnitude / b[1].count;
      return avgA - avgB;
    });

    return validCandidates[0][0];
  }

  static clean(rawAmount: any): string {
    if (rawAmount === null || rawAmount === undefined) return "0.00";
    let strAmount = String(rawAmount).trim();
    if (!strAmount || strAmount === '') return "0.00";

    // PROTEÇÃO V11: Se o valor contiver muitas letras ou for uma frase, ignoramos.
    // Isso evita que o nome de alguém (ex: "JOSE SILVA") seja interpretado como número.
    if (/[a-zA-Z]{3,}/.test(strAmount) && !strAmount.toUpperCase().endsWith('D') && !strAmount.toUpperCase().endsWith('C')) {
        return "0.00";
    }

    let cleaned = strAmount.replace(/[R$\s]/g, '');
    if (/\d{1,2}:\d{2}/.test(cleaned)) return "0.00";

    const isNegative = 
        cleaned.includes('-') || 
        cleaned.includes('(') || 
        cleaned.toUpperCase().endsWith('D'); 

    cleaned = cleaned.replace(/[^0-9.,]/g, '');

    const hasComma = cleaned.includes(',');
    const hasDot = cleaned.includes('.');

    if (hasComma && hasDot) {
        const lastDot = cleaned.lastIndexOf('.');
        const lastComma = cleaned.lastIndexOf(',');
        if (lastDot < lastComma) {
            cleaned = cleaned.replace(/\./g, '').replace(',', '.');  
        } else {
            cleaned = cleaned.replace(/,/g, ''); 
        }
    } 
    else if (hasComma) {
        const parts = cleaned.split(',');
        if (parts.length > 2) {
            cleaned = cleaned.replace(/,/g, '');
        } 
        else if (parts.length === 2) {
            const decimalPart = parts[1];
            if (decimalPart.length === 3) {
                cleaned = cleaned.replace(/,/g, '');
            } else {
                cleaned = cleaned.replace(',', '.');
            }
        }
    } 
    else if (hasDot) {
        const parts = cleaned.split('.');
        if (parts.length > 2) {
            cleaned = cleaned.replace(/\./g, '');
        } 
        else if (parts.length === 2) {
            const decimalPart = parts[1];
            if (decimalPart.length === 3) {
                cleaned = cleaned.replace(/\./g, '');
            }
        }
    }

    const val = parseFloat(cleaned);
    if (isNaN(val)) return "0.00";

    return (isNegative ? -Math.abs(val) : Math.abs(val)).toFixed(2);
  }

  private static simpleParse(val: any): number | null {
    if (val === null || val === undefined) return null;
    const s = String(val).trim();
    if (s.length < 1 || s.includes(':')) return null;
    const cleanedStr = this.clean(s);
    const parsed = parseFloat(cleanedStr);
    return isNaN(parsed) ? null : parsed;
  }
}

