                // 2. VALOR: Limpeza mínima para garantir que seja um número válido.
                const standardizedAmount = AmountResolver.clean(rawAmount);
                const numericValue = parseFloat(standardizedAmount);

                // 3. DESCRIÇÃO: ZERO NORMALIZAÇÃO. O que está no arquivo vai para o relatório.
                const finalDesc = rawDesc;

                if (finalDesc.length > 0 && !isNaN(numericValue)) {
                    transactions.push({
                        id: `dbmodel-${matchingModel.id}-${index}-${Date.now()}`,
