import { Transaction, FileModel } from '../../types';
import { Fingerprinter } from '../processors/Fingerprinter';
import { StrategyEngine } from '../strategies';

/**
 * 🎛️ INGESTION ORCHESTRATOR (V8 - WYSIWYG TOTAL FIX)
 */
export const IngestionOrchestrator = {
    /**
     * Normaliza o conteúdo bruto transformando espaços duplos em delimitadores virtuais (;).
     * Esta é a "Fonte da Verdade" que garante que o que se vê no Laboratório é o que se processa no Relatório.
     */
    normalizeRawContent(content: string): string {
        if (!content) return "";

        // Remove linhas vazias e normaliza delimitadores baseados em espaços (comum em PDFs do SICOOB/Itaú)
        return content.split(/\r?\n/)
            .map(line => {
                const trimmed = line.trim();
                if (!trimmed) return "";

                // REGRA CRUCIAL: Se não tem delimitador padrão (; ou tab) mas tem espaços duplos, 
                // soldamos como colunas para manter a paridade com a grade visual do Laboratório.
                if (!trimmed.includes(';') && !trimmed.includes('\t') && trimmed.includes('  ')) {
                    return trimmed.replace(/\s{2,}/g, ';');
                }
                return trimmed;
            })
            .filter(l => l.length > 0)
            .join('\n');
    },

    async processFile(
        file: File, 
        content: string, 
        models: FileModel[], 
        globalKeywords: string[]
    ): Promise<any> {
        const fileNameLower = file.name.toLowerCase();
        const isExcel = fileNameLower.endsWith('.xlsx') || fileNameLower.endsWith('.xls');

        // 1. Normalização idêntica ao Laboratório
        const processedContent = isExcel ? content : this.normalizeRawContent(content);

        // 2. GERAÇÃO DE DNA sobre o conteúdo estruturado
        const fingerprint = Fingerprinter.generate(processedContent);

        // 3. ROTEAMENTO
        const hasModel = models.some(m => m.is_active);
        const result = await StrategyEngine.process(
            file.name, 
            processedContent, 
            models, 
            hasModel ? [] : globalKeywords
        );

        return {
            source: 'upload',
            transactions: result.transactions,
            strategyUsed: result.strategyName,
            fingerprint: fingerprint || { columnCount: 0 }
        };
    },

    async processVirtualData(
        sourceName: string,
        transactions: Transaction[],
        globalKeywords: string[]
    ): Promise<any> {
        const virtualContent = transactions.map(t => `${t.date};${t.description};${t.amount}`).join('\n');
        const fingerprint = Fingerprinter.generate(virtualContent);

        return {
            source: 'virtual',
            transactions: transactions,
            strategyUsed: `Virtual:${sourceName}`,
            fingerprint: fingerprint || { columnCount: 3 }
        };
    }
};

