        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, paymentMethodColumnIndex, skipRowsStart } = matchingModel.mapping;
        const delimiter = matchingModel.fingerprint.delimiter || ';'; 

        const transactions: Transaction[] = [];
        const lines = content.split(/\r?\n/);

        lines.forEach((line, index) => {
            if (index < (skipRowsStart || 0)) return;
