                const stdAmount = AmountResolver.clean(rawAmount);
                const numericValue = parseFloat(stdAmount);
                if (isNaN(numericValue) || (numericValue === 0 && rawDesc.length < 3)) return;

                const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);

                transactions.push({
                    id: `fid-${matchingModel.id}-${index}-${Date.now()}`,
                    date: isoDate || (rawDate ? `ERR:${rawDate}` : new Date().toISOString().split('T')[0]),
                    description: rawDesc,
